solution_code:
#include <iostream>
#include <iomanip>

int main()
{
    int a = 0;
    int b = 0;
    std::cin >> a >> b;

    std::cout << "int: " << a / b << '\n';
    std::cout << std::fixed << std::setprecision(2);
    std::cout << "float: " << static_cast<double>(a) / b << '\n';

    return 0;
}

