solution_code:
#include <iostream>

int applyUpdates(int x)
{
    x += 5;
    x *= 3;
    x -= 2;
    x /= 2;
    return x;
}

int main()
{
    int n = 0;
    std::cin >> n;
    std::cout << "result: " << applyUpdates(n) << '\n';
    return 0;
}
